import pymongo
from bson.code import Code

def connect_to_mongodb(host='localhost', port=27017, db_name='advanced_filtering_db'):
    """Establishes a connection to MongoDB."""
    client = pymongo.MongoClient(host, port)
    return client[db_name]

def create_sample_data(db):
    """Creates sample data if the collection is empty."""
    collection = db.user_data
    if collection.count_documents({}) == 0:
        print("Inserting sample data...")
        sample_data = [
            {"name": "Alice", "age": 30, "city": "New York", "tags": ["developer", "python"]},
            {"name": "Bob", "age": 24, "city": "London", "tags": ["designer", "frontend"]},
            {"name": "Charlie", "age": 35, "city": "New York", "tags": ["manager", "backend"]},
            {"name": "David", "age": 29, "city": "Paris", "tags": ["developer", "java"]},
            {"name": "Eve", "age": 40, "city": "London", "tags": ["architect", "cloud"]},
            {"name": "Frank", "age": 22, "city": "Berlin", "tags": ["intern", "python"]},
        ]
        collection.insert_many(sample_data)
        print("Sample data inserted.")
    else:
        print("Sample data already exists.")

def query_with_where(db, javascript_expression):
    """
    Executes a MongoDB query using the $where operator with a server-side JavaScript expression.
    """
    collection = db.user_data
    try:
        # The $where operator expects a string containing the JavaScript expression
        # or a Code object. Using a string directly is often sufficient.
        results = collection.find({"$where": javascript_expression})
        return list(results)
    except pymongo.errors.OperationFailure as e:
        print(f"Error executing JavaScript expression: {e}")
        print("Please ensure your JavaScript expression is valid and safe.")
        return []
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return []

def main():
    db = connect_to_mongodb()
    create_sample_data(db)

    print("\n--- Advanced Data Filtering Service ---")
    print("Enter JavaScript expressions to filter documents using MongoDB's $where operator.")
    print("Examples:")
    print("  - 'this.age > 30'")
    print("  - 'this.name.length > 4 && this.city == \"New York\"'")
    print("  - 'this.tags.includes(\"python\")'")
    print("  - 'obj.age % 2 == 0' (using 'obj' alias, though 'this' is more common)")
    print("  - 'function() { return this.age > 30; }'") # Can also be a function definition

    while True:
        user_input = input("\nEnter JavaScript filter expression (or 'exit' to quit): ").strip()
        if user_input.lower() == 'exit':
            break

